const rawText = ($json.master_text || '').trim();
const languageHint = $json.language_hint || 'FR';

const cleanedText = rawText
  .replace(/\r/g, '')
  .replace(/[ \t]+/g, ' ')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

const sections = {
  title: cleanedText.split('\n')[0] || '',
  hasDeadline: /date limite|deadline|closing date|au plus tard/i.test(cleanedText),
  hasLocation: /Kinshasa|Lubumbashi|RDC|Congo|Ngaliema|Haut-Katanga|Lualaba/i.test(cleanedText),
  hasBudget: /budget|USD|CDF|montant|financement/i.test(cleanedText),
  hasWorks: /travaux|construction|ouvrages|assainissement|services|supply/i.test(cleanedText)
};

return [
  {
    json: {
      masterText: cleanedText,
      language: languageHint,
      sections,
      metadata: {
        length: cleanedText.length,
        wordCount: cleanedText ? cleanedText.split(/\s+/).length : 0
      }
    }
  }
];

const text = ($json.text || '').trim();

const textLength = text.length;
const wordCount = text ? text.split(/\s+/).length : 0;

const hasEnoughText = textLength > 500 && wordCount > 80;

const weirdCharMatches = text.match(/[�□■▪▫◦•]/g) || [];
const weirdCharRatio = textLength ? weirdCharMatches.length / textLength : 1;

const likelyBadExtraction =
  !hasEnoughText ||
  weirdCharRatio > 0.02 ||
  /^[\[\]\(\)\-–—_\s.:/\\|]+$/.test(text);

return [
  {
    json: {
      text,
      textLength,
      wordCount,
      hasEnoughText,
      weirdCharRatio,
      likelyBadExtraction,
      route: likelyBadExtraction ? 'ocr' : 'clean'
    }
  }
];

return [
  {
    json: {
      master_text: $json.clean_text,
      language_hint: $json.clean_text.includes("Avis d’Appel") ? "FR" : "EN"
    }
  }
];

const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');

return [
  {
    json: {
      text: buffer.toString('utf8')
    }
  }
];

const raw = $json.output?.[0]?.content?.[0]?.text || '';

if (!raw) {
  throw new Error('Metadata raw text not found at output[0].content[0].text');
}

let cleaned = raw.trim();

if (cleaned.startsWith('```json')) {
  cleaned = cleaned.replace(/^```json\s*/i, '').replace(/\s*```$/, '');
} else if (cleaned.startsWith('```')) {
  cleaned = cleaned.replace(/^```\s*/i, '').replace(/\s*```$/, '');
}

let parsed;

try {
  parsed = JSON.parse(cleaned);
} catch (error) {
  throw new Error('Metadata JSON parse failed: ' + error.message + '\nRaw output: ' + raw);
}

return [{ json: parsed }];

