const item = $input.first().json;

// --- Safe score extraction
const complianceScore = Number(item.compliance?.score || 0);
const technicalFitScore = Number(item.technical_fit?.score || 0);
const financialScore = Number(item.financial?.score || 0);
const riskScore = Number(item.risk?.score || 0);
const opportunityScore = Number(item.opportunity?.score || 0);

// --- Weights
const weights = {
  compliance: 0.25,
  technical_fit: 0.25,
  financial: 0.20,
  risk: 0.15,
  opportunity: 0.15,
};

// --- Weighted score
const finalScore =
  (complianceScore * weights.compliance) +
  (technicalFitScore * weights.technical_fit) +
  (financialScore * weights.financial) +
  (riskScore * weights.risk) +
  (opportunityScore * weights.opportunity);

// --- Counts
const redFlagCount =
  (item.compliance?.red_flags?.length || 0) +
  (item.technical_fit?.red_flags?.length || 0) +
  (item.financial?.red_flags?.length || 0) +
  (item.risk?.red_flags?.length || 0) +
  (item.opportunity?.red_flags?.length || 0);

const missingInfoCount =
  (item.compliance?.missing_information?.length || 0) +
  (item.technical_fit?.missing_information?.length || 0) +
  (item.financial?.missing_information?.length || 0) +
  (item.risk?.missing_information?.length || 0) +
  (item.opportunity?.missing_information?.length || 0);

// --- Confidence check
const confidenceValues = [
  item.compliance?.confidence,
  item.technical_fit?.confidence,
  item.financial?.confidence,
  item.risk?.confidence,
  item.opportunity?.confidence,
].map(v => String(v || '').toLowerCase());

const lowConfidenceCount = confidenceValues.filter(v =>
  v.includes('low') || v.includes('medium')
).length;

// --- Decision logic
let aiDecision = "REVIEW";
let decisionReason = "Balanced result. Requires management review.";

if (
  finalScore >= 80 &&
  redFlagCount <= 2 &&
  missingInfoCount <= 3 &&
  complianceScore >= 70 &&
  technicalFitScore >= 70
) {
  aiDecision = "GO";
  decisionReason = "Strong overall tender profile with manageable risk and sufficient alignment.";
} else if (
  finalScore < 60 ||
  complianceScore < 50 ||
  technicalFitScore < 50 ||
  redFlagCount >= 6
) {
  aiDecision = "NO-GO";
  decisionReason = "Tender presents weak alignment, major compliance/technical concerns, or excessive risk.";
}

// --- Aggregate lists
const aggregatedRedFlags = [
  ...(item.compliance?.red_flags || []),
  ...(item.technical_fit?.red_flags || []),
  ...(item.financial?.red_flags || []),
  ...(item.risk?.red_flags || []),
  ...(item.opportunity?.red_flags || []),
];

const aggregatedMissingInformation = [
  ...(item.compliance?.missing_information || []),
  ...(item.technical_fit?.missing_information || []),
  ...(item.financial?.missing_information || []),
  ...(item.risk?.missing_information || []),
  ...(item.opportunity?.missing_information || []),
];

// --- Optional warnings
const warnings = [];

if (lowConfidenceCount >= 2) {
  warnings.push("Multiple agents returned low or medium confidence.");
}
if (missingInfoCount >= 4) {
  warnings.push("Tender contains significant missing information.");
}
if (redFlagCount >= 4) {
  warnings.push("Tender contains several red flags across evaluation areas.");
}

// --- Final output
return [
  {
    json: {
      ...item,

      final_score: Math.round(finalScore * 100) / 100,
      ai_decision: aiDecision,
      decision_reason: decisionReason,

      red_flag_count: redFlagCount,
      missing_info_count: missingInfoCount,
      low_confidence_count: lowConfidenceCount,

      aggregated_red_flags: aggregatedRedFlags,
      aggregated_missing_information: aggregatedMissingInformation,
      warnings,
    }
  }
];

