const data = $json;

// Get agent safely
const compliance = data.compliance || {};
const technical = data.technical || data.technical_fit || {};
const financial = data.financial || {};
const risk = data.risk || {};
const opportunity = data.opportunity || {};

// Metadata
const sector = (data.metadata?.sector || "").toLowerCase();
const subsector = (data.metadata?.subsector || "").toLowerCase();

// Default weights
let weights = {
  compliance: 0.25,
  technical: 0.25,
  financial: 0.20,
  risk: 0.15,
  opportunity: 0.15
};

// Sector-specific weighting
if (
  sector.includes("technology") ||
  sector.includes("ict") ||
  sector.includes("information") ||
  subsector.includes("computer") ||
  subsector.includes("software") ||
  subsector.includes("it")
) {
  weights = {
    compliance: 0.20,
    technical: 0.35,
    financial: 0.15,
    risk: 0.15,
    opportunity: 0.15
  };
}

if (
  sector.includes("construction") ||
  sector.includes("civil") ||
  sector.includes("water") ||
  sector.includes("sanitation") ||
  subsector.includes("works")
) {
  weights = {
    compliance: 0.25,
    technical: 0.30,
    financial: 0.20,
    risk: 0.20,
    opportunity: 0.05
  };
}

if (
  sector.includes("supply") ||
  sector.includes("fourniture") ||
  subsector.includes("equipment") ||
  subsector.includes("équipement")
) {
  weights = {
    compliance: 0.25,
    technical: 0.20,
    financial: 0.25,
    risk: 0.15,
    opportunity: 0.15
  };
}

if (
  sector.includes("service") ||
  subsector.includes("consulting") ||
  subsector.includes("maintenance")
) {
  weights = {
    compliance: 0.25,
    technical: 0.25,
    financial: 0.15,
    risk: 0.15,
    opportunity: 0.20
  };
}

// Scores
const complianceScore = Number(compliance.score || 0);
const technicalScore = Number(technical.score || 0);
const financialScore = Number(financial.score || 0);
const riskScore = Number(risk.score || 0);
const opportunityScore = Number(opportunity.score || 0);

// Count issues
const countArray = (value) => Array.isArray(value) ? value.length : 0;

const complianceRedFlags = countArray(compliance.red_flags);
const technicalRedFlags = countArray(technical.red_flags);
const financialRedFlags = countArray(financial.red_flags);
const riskRedFlags = countArray(risk.red_flags);
const opportunityRedFlags = countArray(opportunity.red_flags);

const totalRedFlags =
  complianceRedFlags +
  technicalRedFlags +
  financialRedFlags +
  riskRedFlags +
  opportunityRedFlags;

const totalMissingInfo =
  countArray(compliance.missing_information) +
  countArray(technical.missing_information) +
  countArray(financial.missing_information) +
  countArray(risk.missing_information) +
  countArray(opportunity.missing_information);

// Base weighted score
let finalScore =
  complianceScore * weights.compliance +
  technicalScore * weights.technical +
  financialScore * weights.financial +
  riskScore * weights.risk +
  opportunityScore * weights.opportunity;

// Smart penalties
let penalty = 0;

penalty += totalRedFlags * 2;
penalty += totalMissingInfo * 1;

// Critical score penalties
if (complianceScore < 50) penalty += 15;
if (technicalScore < 50) penalty += 12;
if (financialScore < 45) penalty += 10;
if (riskScore < 45) penalty += 12;

// Risk cap
penalty = Math.min(penalty, 30);

finalScore = finalScore - penalty;
finalScore = Math.max(0, Math.min(100, finalScore));

// Decision logic
let decision = "REVIEW";

if (
  finalScore >= 75 &&
  complianceScore >= 65 &&
  technicalScore >= 65 &&
  riskScore >= 55 &&
  totalRedFlags <= 4
) {
  decision = "GO";
}

if (
  finalScore < 50 ||
  complianceScore < 45 ||
  technicalScore < 45 ||
  riskScore < 40 ||
  totalRedFlags >= 8
) {
  decision = "NO-GO";
}

// Confidence logic
let confidence = "medium";

if (
  totalMissingInfo <= 3 &&
  totalRedFlags <= 4 &&
  complianceScore > 60 &&
  technicalScore > 60
) {
  confidence = "high";
}

if (
  totalMissingInfo >= 6 ||
  totalRedFlags >= 7 ||
  complianceScore < 50 ||
  technicalScore < 50
) {
  confidence = "low";
}

// Executive reason
const decisionReason = `
This tender was evaluated using a sector-adjusted scoring model.

Sector detected: ${data.metadata?.sector || "Not specified"}
Subsector detected: ${data.metadata?.subsector || "Not specified"}

Weighted Evaluation:
- Compliance: ${complianceScore}/100
- Technical Fit: ${technicalScore}/100
- Financial Value: ${financialScore}/100
- Risk Position: ${riskScore}/100
- Business Opportunity: ${opportunityScore}/100

Risk Adjustment:
- Total red flags identified: ${totalRedFlags}
- Missing information items: ${totalMissingInfo}
- Penalty applied: ${penalty} points

Final Score: ${Math.round(finalScore)}/100
Final Recommendation: ${decision}

Business Interpretation:
${
  decision === "GO"
    ? "The tender appears attractive and reasonably manageable. The company may proceed, subject to final human review and pricing validation."
    : decision === "REVIEW"
    ? "The tender has potential, but there are important gaps or risks that should be reviewed before committing resources."
    : "The tender presents weak alignment, major compliance or technical concerns, or excessive risk. It is not recommended to proceed without major clarification."
}
`;

return [
  {
    json: {
      ...data,
      scoring_model: "Sector-Weighted V2",
      scoring_weights: weights,
      final_score: Math.round(finalScore),
      decision,
      confidence,
      total_red_flags: totalRedFlags,
      total_missing_information: totalMissingInfo,
      penalty_applied: penalty,
      decision_reason: decisionReason.trim()
    }
  }
];

const score = $json.final_score;
const compliance = $json.compliance_score;
const risk = $json.risk_score;

let decision = "";
let reason = "";
let trigger = [];

if (compliance < 70) {
  decision = "NO-GO";
  trigger.push("Low compliance");
}

if (risk >= 80) {
  decision = "NO-GO";
  trigger.push("High risk");
}

if (!decision) {
  if (score >= 75) {
    decision = "GO";
    trigger.push("Strong overall score");
  } else if (score >= 60) {
    decision = "REVIEW";
    trigger.push("Moderate score");
  } else {
    decision = "NO-GO";
    trigger.push("Low score");
  }
}

reason = `Decision based on: ${trigger.join(", ")}`;

return [{
  json: {
    ...$json,
    ai_decision: decision,
    decision_reason: reason,
    decision_triggers: trigger
  }
}];
